+//! SVG element primitives.
+//!
+//! Provides structs for creating SVG elements like rect, circle, path, etc.
+//! with a fluent builder API.
+
+use std::fmt::Write;
+
+use crate::attributes::Attributes;
+
+/// Types of SVG elements.
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum ElementKind {
+    Rect,
+    Circle,
+    Ellipse,
+    Line,
+    Polyline,
+    Polygon,
+    Path,
+    Text,
+    Tspan,
+    Group,
+    Use,
+    ClipPath,
+    Marker,
+    Defs,
+    LinearGradient,
+    RadialGradient,
+    Stop,
+    Filter,
+    FeDropShadow,
+    FeGaussianBlur,
+    FeOffset,
+    FeFlood,
+    FeComposite,
+    FeMerge,
+    FeMergeNode,
+}
+
+impl ElementKind {
+    /// Get the SVG tag name for this element kind.
+    #[must_use]
+    pub const fn tag_name(self) -> &'static str {
+        match self {
+            Self::Rect => "rect",
+            Self::Circle => "circle",
+            Self::Ellipse => "ellipse",
+            Self::Line => "line",
+            Self::Polyline => "polyline",
+            Self::Polygon => "polygon",
+            Self::Path => "path",
+            Self::Text => "text",
+            Self::Tspan => "tspan",
+            Self::Group => "g",
+            Self::Use => "use",
+            Self::ClipPath => "clipPath",
+            Self::Marker => "marker",
+            Self::Defs => "defs",
+            Self::LinearGradient => "linearGradient",
+            Self::RadialGradient => "radialGradient",
+            Self::Stop => "stop",
+            Self::Filter => "filter",
+            Self::FeDropShadow => "feDropShadow",
+            Self::FeGaussianBlur => "feGaussianBlur",
+            Self::FeOffset => "feOffset",
+            Self::FeFlood => "feFlood",
+            Self::FeComposite => "feComposite",
+            Self::FeMerge => "feMerge",
+            Self::FeMergeNode => "feMergeNode",
+        }
+    }
+
+    /// Check if this element is self-closing (has no children).
+    #[must_use]
+    pub const fn is_self_closing(self) -> bool {
+        matches!(
+            self,
+            Self::Rect
+                | Self::Circle
+                | Self::Ellipse
+                | Self::Line
+                | Self::Polyline
+                | Self::Polygon
+                | Self::Path
+                | Self::Use
+                | Self::Stop
+                | Self::FeDropShadow
+                | Self::FeGaussianBlur
+                | Self::FeOffset
+                | Self::FeFlood
+                | Self::FeMergeNode
+        )
+    }
+}
+
+/// An SVG element with attributes and optional children.
+#[derive(Debug, Clone)]
+pub struct Element {
+    kind: ElementKind,
+    attrs: Attributes,
+    children: Vec<Element>,
+    text_content: Option<String>,
+}
+
+impl Element {
+    /// Create a new element of the given kind.
+    #[must_use]
+    pub fn new(kind: ElementKind) -> Self {
+        Self {
+            kind,
+            attrs: Attributes::new(),
+            children: Vec::new(),
+            text_content: None,
+        }
+    }
+
+    // Factory methods for common elements
+
+    /// Create a rect element.
+    #[must_use]
+    pub fn rect() -> Self {
+        Self::new(ElementKind::Rect)
+    }
+
+    /// Create a circle element.
+    #[must_use]
+    pub fn circle() -> Self {
+        Self::new(ElementKind::Circle)
+    }
+
+    /// Create an ellipse element.
+    #[must_use]
+    pub fn ellipse() -> Self {
+        Self::new(ElementKind::Ellipse)
+    }
+
+    /// Create a line element.
+    #[must_use]
+    pub fn line() -> Self {
+        Self::new(ElementKind::Line)
+    }
+
+    /// Create a polyline element.
+    #[must_use]
+    pub fn polyline() -> Self {
+        Self::new(ElementKind::Polyline)
+    }
+
+    /// Create a polygon element.
+    #[must_use]
+    pub fn polygon() -> Self {
+        Self::new(ElementKind::Polygon)
+    }
+
+    /// Create a path element.
+    #[must_use]
+    pub fn path() -> Self {
+        Self::new(ElementKind::Path)
+    }
+
+    /// Create a text element.
+    #[must_use]
+    pub fn text() -> Self {
+        Self::new(ElementKind::Text)
+    }
+
+    /// Create a tspan element.
+    #[must_use]
+    pub fn tspan() -> Self {
+        Self::new(ElementKind::Tspan)
+    }
+
+    /// Create a group element.
+    #[must_use]
+    pub fn group() -> Self {
+        Self::new(ElementKind::Group)
+    }
+
+    /// Create a use element.
