+        ArrowType::ThickArrow => (None, Some("url(#arrow-filled)"), "#333"),
+        ArrowType::DottedArrow => (Some("5,5"), Some("url(#arrow-end)"), "#666"),
+        ArrowType::Circle => (None, Some("url(#arrow-circle)"), "#333"),
+        ArrowType::Cross => (None, Some("url(#arrow-cross)"), "#333"),
