+                        .y(ly - label_height / 2.0 - 2.0)
+                        .width(label_width)
+                        .height(label_height)
+                        .fill("#fff")
+                        .stroke("none")
+                        .rx(2.0),
+                );
+
+                // Add label text
+                group = group.child(
+                    TextBuilder::new(&label.text)
+                        .x(lx)
+                        .y(ly + config.font_size / 4.0)
+                        .font_family(&config.font_family)
+                        .font_size(config.font_size * 0.85)
+                        .anchor(TextAnchor::Middle)
+                        .fill("#666")
+                        .class("edge-label")
+                        .build(),
+                );
+
+                return group;
+            }
+        }
+    }
+
+    elem
 }

