+/// Builder for SVG text elements.
+#[derive(Debug, Clone)]
+pub struct TextBuilder {
+    text: String,
+    x: f32,
+    y: f32,
+    font_family: Option<String>,
+    font_size: Option<f32>,
+    font_weight: Option<String>,
+    font_style: Option<String>,
+    fill: Option<String>,
+    anchor: TextAnchor,
+    baseline: DominantBaseline,
+    class: Option<String>,
+    line_height: f32,
